# from winbase.h
STDOUT = -11
STDERR = -12

ENABLE_VIRTUAL_TERMINAL_PROCESSING = 0x0004

try:
    import ctypes
    from ctypes import LibraryLoader
    windll = LibraryLoader(ctypes.WinDLL)
    from ctypes import wintypes
except (AttributeError, ImportError):
    windll = None
    SetConsoleTextAttribute = lambda *_: None
    winapi_test = lambda *_: None
else:
    from ctypes import byref, Structure, c_char, POINTER

    COORD = wintypes._COORD

    class CONSOLE_SCREEN_BUFFER_INFO(Structure):
        """Structure representing CONSOLE_SCREEN_BUFFER_INFO from wincon.h."""
        _fields_ = [
            ("dwSize", COORD),
            ("dwCursorPosition", COORD),
            ("wAttributes", wintypes.WORD),
            ("srWindow", wintypes.SMALL_RECT),
            ("dwMaximumWindowSize", COORD),
        ]
        def __str__(self):
            """Return a human-readable representation of the console buffer info."""
            return '(%d,%d,%d,%d,%d,%d,%d,%d,%d,%d,%d)' % (
                self.dwSize.Y, self.dwSize.X
                , self.dwCursorPosition.Y, self.dwCursorPosition.X
                , self.wAttributes
                , self.srWindow.Top, self.srWindow.Left, self.srWindow.Bottom, self.srWindow.Right
                , self.dwMaximumWindowSize.Y, self.dwMaximumWindowSize.X
            )

    _GetStdHandle = windll.kernel32.GetStdHandle
    _GetStdHandle.argtypes = [
        wintypes.DWORD,
    ]
    _GetStdHandle.restype = wintypes.HANDLE

    _GetConsoleScreenBufferInfo = windll.kernel32.GetConsoleScreenBufferInfo
    _GetConsoleScreenBufferInfo.argtypes = [
        wintypes.HANDLE,
        POINTER(CONSOLE_SCREEN_BUFFER_INFO),
    ]
    _GetConsoleScreenBufferInfo.restype = wintypes.BOOL

    _SetConsoleTextAttribute = windll.kernel32.SetConsoleTextAttribute
    _SetConsoleTextAttribute.argtypes = [
        wintypes.HANDLE,
        wintypes.WORD,
    ]
    _SetConsoleTextAttribute.restype = wintypes.BOOL

    _SetConsoleCursorPosition = windll.kernel32.SetConsoleCursorPosition
    _SetConsoleCursorPosition.argtypes = [
        wintypes.HANDLE,
        COORD,
    ]
    _SetConsoleCursorPosition.restype = wintypes.BOOL

    _FillConsoleOutputCharacterA = windll.kernel32.FillConsoleOutputCharacterA
    _FillConsoleOutputCharacterA.argtypes = [
        wintypes.HANDLE,
        c_char,
        wintypes.DWORD,
        COORD,
        POINTER(wintypes.DWORD),
    ]
    _FillConsoleOutputCharacterA.restype = wintypes.BOOL

    _FillConsoleOutputAttribute = windll.kernel32.FillConsoleOutputAttribute
    _FillConsoleOutputAttribute.argtypes = [
        wintypes.HANDLE,
        wintypes.WORD,
        wintypes.DWORD,
        COORD,
        POINTER(wintypes.DWORD),
    ]
    _FillConsoleOutputAttribute.restype = wintypes.BOOL

    _SetConsoleTitleW = windll.kernel32.SetConsoleTitleW
    _SetConsoleTitleW.argtypes = [
        wintypes.LPCWSTR
    ]
    _SetConsoleTitleW.restype = wintypes.BOOL

    _GetConsoleMode = windll.kernel32.GetConsoleMode
    _GetConsoleMode.argtypes = [
        wintypes.HANDLE,
        POINTER(wintypes.DWORD)
    ]
    _GetConsoleMode.restype = wintypes.BOOL

    _SetConsoleMode = windll.kernel32.SetConsoleMode
    _SetConsoleMode.argtypes = [
        wintypes.HANDLE,
        wintypes.DWORD
    ]
    _SetConsoleMode.restype = wintypes.BOOL

    def _winapi_test(handle):
        """Test whether the given handle refers to a valid console screen buffer."""
        csbi = CONSOLE_SCREEN_BUFFER_INFO()
        success = _GetConsoleScreenBufferInfo(
            handle, byref(csbi))
        return bool(success)

    def winapi_test():
        """Return True if either STDOUT or STDERR refers to a valid console."""
        return any(_winapi_test(h) for h in
                   (_GetStdHandle(STDOUT), _GetStdHandle(STDERR)))

    def GetConsoleScreenBufferInfo(stream_id=STDOUT):
        """Retrieve the CONSOLE_SCREEN_BUFFER_INFO for the given stream handle."""
        handle = _GetStdHandle(stream_id)
        csbi = CONSOLE_SCREEN_BUFFER_INFO()
        _GetConsoleScreenBufferInfo(handle, byref(csbi))
        return csbi

    def SetConsoleTextAttribute(stream_id, attrs):
        """Set the text attributes (colors, intensity, etc.) for the given stream."""
        handle = _GetStdHandle(stream_id)
        return _SetConsoleTextAttribute(handle, attrs)

    def SetConsoleCursorPosition(stream_id, position):
        """Set the cursor position for the given stream.

        Position may be a COORD instance or a (X, Y) tuple.
        """
        handle = _GetStdHandle(stream_id)
        if not isinstance(position, COORD):
            # Expect a (X, Y) tuple
            position = COORD(position[0], position[1])
        return _SetConsoleCursorPosition(handle, position)

    def FillConsoleOutputCharacter(stream_id, char, length, coord):
        """Fill the console output with the given character.

        char may be a one-character string or a bytes object. coord may be a COORD
        instance or an (X, Y) tuple. Returns the number of characters written.
        """
        handle = _GetStdHandle(stream_id)
        if isinstance(char, str):
            # Use only the first character and encode as ASCII
            char = char[0].encode('ascii')
        elif isinstance(char, bytes):
            if not char:
                char = b' '
            else:
                char = char[:1]
        else:
            # Fallback: convert to str then take first char
            char = str(char)[0].encode('ascii')

        if not isinstance(coord, COORD):
            coord = COORD(coord[0], coord[1])

        written = wintypes.DWORD(0)
        success = _FillConsoleOutputCharacterA(handle, char, wintypes.DWORD(length), coord, byref(written))
        if not success:
            return 0
        return written.value

    def SetConsoleTitle(title):
        """Set the console window title (wide-character)."""
        return _SetConsoleTitleW(title)

    def GetConsoleMode(stream_id=STDOUT):
        """Get the console mode flags for the given stream. Returns the mode integer or None on failure."""
        handle = _GetStdHandle(stream_id)
        mode = wintypes.DWORD(0)
        success = _GetConsoleMode(handle, byref(mode))
        if not success:
            return None
        return mode.value

    def SetConsoleMode(stream_id, mode):
        """Set the console mode flags for the given stream."""
        handle = _GetStdHandle(stream_id)
        return _SetConsoleMode(handle, mode)